DataSource.SQL:
DECLARE @LastFolderTree VARCHAR(900);
DECLARE @NewApproveRoundGUID uniqueidentifier = ( SELECT ActualApproveRoundGuid FROM usr.ITSMRelease WHERE ID = @ID )
SET @LastFolderTree = COALESCE( CASE WHEN @IsShowCategoryLevel5 = 1 THEN NULLIF(@ITSMCategoryLevel5Ident, '') ELSE NULL END, NULLIF(@ITSMCategoryLevel4Ident, ''), NULLIF(@ITSMCategoryLevel3Ident, ''), NULLIF(@ITSMCategoryLevel2Ident, ''), NULLIF(@ITSMCompanyIdent, '') );
SELECT @ID AS TableID, @FormIdent AS FormIdent, appsf.ApproveOrder AS ApproveOrder, appsf.ApproverType, appsf.ApproverGroupID, appsf.ApproverAccountID, @NewApproveRoundGUID AS ApproveRoundGUID FROM usr.ITSMApproval AS appsf WHERE ApproveRoundGUID = @OldActualApproveRoundGuid AND appsf.TableID = @ID AND appsf.FormIdent = @FormIdent AND appsf.State != @DeletedState

DECLARE @LastFolderTree VARCHAR(900);
DECLARE @NewApproveRoundGUID uniqueidentifier = ( SELECT ActualApproveRoundGuid FROM usr.ITSMRelease WHERE ID = @ID )
SET @LastFolderTree = COALESCE( CASE WHEN @IsShowCategoryLevel5 = 1 THEN NULLIF(@ITSMCategoryLevel5Ident, '') ELSE NULL END, NULLIF(@ITSMCategoryLevel4Ident, ''), NULLIF(@ITSMCategoryLevel3Ident, ''), NULLIF(@ITSMCategoryLevel2Ident, ''), NULLIF(@ITSMCompanyIdent, '') );
SELECT @ID AS TableID, @FormIdent AS FormIdent, appsf.ApproveOrder AS ApproveOrder, appsf.ApproverType, appsf.ApproverGroupID, appsf.ApproverAccountID, @NewApproveRoundGUID AS ApproveRoundGUID FROM usr.ITSMApproval AS appsf WHERE ApproveRoundGUID = @OldActualApproveRoundGuid AND appsf.TableID = @ID AND appsf.FormIdent = @FormIdent AND appsf.State != @DeletedState

DECLARE @LastFolderTree VARCHAR(900);
SET @LastFolderTree = COALESCE( CASE WHEN @IsShowCategoryLevel5 = 1 THEN NULLIF(@ITSMCategoryLevel5Ident, '') ELSE NULL END, NULLIF(@ITSMCategoryLevel4Ident, ''), NULLIF(@ITSMCategoryLevel3Ident, ''), NULLIF(@ITSMCategoryLevel2Ident, ''), NULLIF(@ITSMCompanyIdent, '') );
SELECT (ISNULL(@LastApproveOrder,0) + appsf.ApproveOrder) AS ApproveOrder, appsf.ApproverType, appsf.ApproverGroupID, appsf.ApproverAccountID, @ActualApproveRoundGuid AS ApproveRoundGUID FROM usr.ITSMApproveSubForm AS appsf INNER JOIN usr.ITSMApproveSetting AS appSet ON appSet.ID = appsf.TableID AND appsf.FormIdent = @FormIdent AND appsf.State != @DeletedState INNER JOIN dbo.FolderTree AS folTre ON folTre.Ident = @LastFolderTree INNER JOIN dbo.Folder AS fol ON fol.ID = folTre.FolderID AND fol.FormIdent = @CategoryFormIdent INNER JOIN usr.ITSMCategory AS cat ON cat.ID = fol.TableID AND cat.ITSMApproveSettingID = appSet.ID

IF @ITSMKey IS NULL
BEGIN
  DECLARE
    @CounterIdent VARCHAR(100) = 'ITSM_REL',
    @NextNumber INT

  EXEC @NextNumber = usr.CounterGetNext @CounterIdent, @UserID;

  UPDATE usr.[ITSMRelease]
  SET ITSMKey = CONCAT('REL-', RIGHT('000000' + CAST(@NextNumber AS VARCHAR(6)), 6))
  WHERE ID = @ID
END

DECLARE @ITSMKey VARCHAR(100) = (
  SELECT ITSMKey
  FROM usr.ITSMRelease
  WHERE ID = @ID
)
DECLARE
  @CounterIdent VARCHAR(100) = CONCAT(@ITSMKey, '_S'),
  @NextNumber INT

EXEC @NextNumber = usr.CounterGetNext @CounterIdent, @UserID;

UPDATE usr.ITSMApproval
SET ApproveRoundStartDateTime = GETDATE(),ITSMKey = CONCAT(@ITSMKey, '_S:', @NextNumber)
WHERE ApproveRoundGUID = @ActualApproveRoundGuid

Condition.SQL:
DECLARE @PermissionIDs dbo.ListNVarchar100Type; INSERT INTO @PermissionIDs VALUES ('ITSMOperator');
DECLARE @LastITSMCategoryIdent VARCHAR(900) = @ITSMCategoryLevel2Ident; IF @IsShowCategoryLevel3 = 1 SET @LastITSMCategoryIdent = @ITSMCategoryLevel3Ident IF @IsShowCategoryLevel4 = 1 SET @LastITSMCategoryIdent = @ITSMCategoryLevel4Ident IF @IsShowCategoryLevel5 = 1 SET @LastITSMCategoryIdent = @ITSMCategoryLevel5Ident
SELECT IIF( EXISTS( SELECT NULL FROM usr.ITSM_GetAllowedFolderTreeByAccountAndPermissionAndSegmentType(@UserID,@FolderGroupSegmentIdent,'ITSMReleaseSegment',@PermissionIDs) WHERE FolderTreeIdent = @LastITSMCategoryIdent ) OR ISNULL(@ID, 0) != 0 , 0, 1)
